mapper.select:
SELECT g.id, g.goods_name, g.goods_sn, g.category, g.brand_id, g.spec_info, g.cover_img, g.sort, g.create_time, g.update_time, IFNULL(gs.shop_sale_price, 0) AS shop_sale_price, IFNULL(gs.shop_stock, 0) AS shop_stock, IFNULL(gs.is_shop_shelf, 0) AS is_shop_shelf FROM sys_goods g
LEFT JOIN sys_goods_shop gs ON g.id = gs.goods_id AND gs.shop_id = #{query.shopId}
INNER JOIN sys_goods_shop gs ON g.id = gs.goods_id AND gs.shop_id = #{query.shopId}
AND g.goods_name LIKE CONCAT('%', #{query.goodsName}, '%')
AND g.brand_id = #{query.brandId}
AND gs.is_shop_shelf = #{query.isShopShelf}
ORDER BY g.create_time DESC
